import { useEffect } from 'react';

interface HeadOptions {
  title?: string;
  description?: string;
  ogTitle?: string;
  ogDescription?: string;
  ogImage?: string;
  ogType?: string;
  canonical?: string;
}

const SITE_NAME = 'TailorMeSwiftly';
const DEFAULT_DESC = 'AI-powered resume tailoring & 26 career tools to supercharge your job search.';
const DEFAULT_IMAGE = 'https://tailormeswiftly.com/og-image.png';

/**
 * Sets document title, meta description, and OpenGraph tags per page.
 * Tags are cleaned up on unmount.
 */
export function useDocumentHead(options: HeadOptions) {
  useEffect(() => {
    const prev = document.title;
    const title = options.title ? `${options.title} | ${SITE_NAME}` : SITE_NAME;
    document.title = title;

    const tags: HTMLMetaElement[] = [];

    function setMeta(property: string, content: string) {
      let el = document.querySelector<HTMLMetaElement>(`meta[property="${property}"]`)
        || document.querySelector<HTMLMetaElement>(`meta[name="${property}"]`);
      if (!el) {
        el = document.createElement('meta');
        if (property.startsWith('og:') || property.startsWith('twitter:')) {
          el.setAttribute('property', property);
        } else {
          el.setAttribute('name', property);
        }
        document.head.appendChild(el);
        tags.push(el);
      }
      el.setAttribute('content', content);
    }

    const desc = options.description || DEFAULT_DESC;
    setMeta('description', desc);
    setMeta('og:title', options.ogTitle || options.title || SITE_NAME);
    setMeta('og:description', options.ogDescription || desc);
    setMeta('og:image', options.ogImage || DEFAULT_IMAGE);
    setMeta('og:type', options.ogType || 'website');
    setMeta('og:site_name', SITE_NAME);
    setMeta('twitter:card', 'summary_large_image');
    setMeta('twitter:title', options.ogTitle || options.title || SITE_NAME);
    setMeta('twitter:description', options.ogDescription || desc);

    if (options.canonical) {
      let link = document.querySelector<HTMLLinkElement>('link[rel="canonical"]');
      if (!link) {
        link = document.createElement('link');
        link.rel = 'canonical';
        document.head.appendChild(link);
      }
      link.href = options.canonical;
    }

    return () => {
      document.title = prev;
      tags.forEach(el => el.remove());
    };
  }, [options.title, options.description, options.ogTitle, options.ogDescription, options.ogImage, options.ogType, options.canonical]);
}
