import React from 'react';

interface JsonLdProps {
  data: Record<string, unknown>;
}

/**
 * Injects a JSON-LD structured data script into the page head.
 */
export default function JsonLd({ data }: JsonLdProps) {
  return (
    <script
      type="application/ld+json"
      dangerouslySetInnerHTML={{ __html: JSON.stringify(data) }}
    />
  );
}

/** Schema.org WebApplication for a tool page */
export function toolJsonLd(tool: { name: string; desc: string; slug: string; tier: string }) {
  return {
    '@context': 'https://schema.org',
    '@type': 'WebApplication',
    name: tool.name,
    description: tool.desc,
    url: `https://tailormeswiftly.com/tools/${tool.slug}`,
    applicationCategory: 'BusinessApplication',
    operatingSystem: 'Web',
    offers: tool.tier === 'premium'
      ? { '@type': 'Offer', price: '9.99', priceCurrency: 'USD' }
      : { '@type': 'Offer', price: '0', priceCurrency: 'USD' },
    publisher: {
      '@type': 'Organization',
      name: 'TailorMeSwiftly',
      url: 'https://tailormeswiftly.com',
    },
  };
}

/** Schema.org SoftwareApplication for the main platform */
export function platformJsonLd() {
  return {
    '@context': 'https://schema.org',
    '@type': 'SoftwareApplication',
    name: 'TailorMeSwiftly',
    description: 'AI-powered resume tailoring & 26 career tools to supercharge your job search.',
    url: 'https://tailormeswiftly.com',
    applicationCategory: 'BusinessApplication',
    operatingSystem: 'Web',
    offers: [
      { '@type': 'Offer', name: 'Free', price: '0', priceCurrency: 'USD' },
      { '@type': 'Offer', name: 'Premium', price: '9.99', priceCurrency: 'USD' },
    ],
    featureList: [
      'AI Resume Tailoring',
      'ATS Optimization',
      'Cover Letter Generator',
      'Mock Interview',
      'Salary Negotiator',
      '26+ AI Career Tools',
    ],
  };
}

/** Schema.org BreadcrumbList */
export function breadcrumbJsonLd(items: { name: string; url: string }[]) {
  return {
    '@context': 'https://schema.org',
    '@type': 'BreadcrumbList',
    itemListElement: items.map((item, i) => ({
      '@type': 'ListItem',
      position: i + 1,
      name: item.name,
      item: item.url,
    })),
  };
}
